}

async (page) => {
  await page.goto('http://localhost:9000');
  await page.waitForTimeout(3000);
  // Fill credentials
  await page.locator('#login-name-input').fill('ClaudeBot1');
  await page.locator('#login-password-input').fill('password123');
  // Apply port override before clicking login
  await page.evaluate(() => {
    const g = window.game;
    if (g && g.app) g.app.config.port = 9011;
    // Also try to set it directly on the server config
    if (g && g.app && g.app.server) g.app.server.port = 9011;
  });
  await page.waitForTimeout(500);
  await page.getByRole('button', { name: 'Login' }).click();
  await page.waitForTimeout(12000);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  // Check page text for status
  const bodyText = await page.evaluate(() => document.body.innerText.substring(0, 500));
  return bodyText;
}
